void dispTwoDigit(int val) {
	val = constrain(val, 0, 99);
	dispNum(val / 10, val % 10);
}

// ============================================================
// ステッピングモータヘルパー
// ============================================================
// CW: phase 0→1→2→3→0...   CCW: 逆順
const int SM_PHASE[4] = { 0x9, 0xc, 0x6, 0x3 };  // stepm_init() の A,B,nA,nB

void motorUpdate() {
	unsigned long now = millis();
	if (now - motorPrevMs < MOTOR_INTERVAL) return;
	motorPrevMs = now;

	if (motorStep < motorTarget) {
		smPhase = (smPhase + 1) & 3;
		lm.bit.SM = SM_PHASE[smPhase];
		motorStep++;
	} else if (motorStep > motorTarget) {
		smPhase = (smPhase - 1 + 4) & 3;
		lm.bit.SM = SM_PHASE[smPhase];
		motorStep--;
	} else {
		lm.bit.SM = 0x00;  // 停止(励磁オフ)
	}
}

